type CandidateEntry = { cell: Cell; neighborCount: number };

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(([x, y]) => keyOf(x, y)));
  const candidates = new Map<string, CandidateEntry>();

  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const cell: Cell = [x + dx, y + dy];
      const key = keyOf(cell[0], cell[1]);
      const existing = candidates.get(key);
      if (existing) {
        existing.neighborCount += 1;
      } else {
        candidates.set(key, { cell, neighborCount: 1 });
      }
    }
  }

  const next: Cell[] = [];
  for (const [key, { cell, neighborCount }] of candidates) {
    if (neighborCount === 3 || (neighborCount === 2 && alive.has(key))) {
      next.push(cell);
    }
  }
  return next;
}

